			 float *coord_d,
			 float * work_mem_d,			
			 int *center_table_d,
			 char *switch_membership_d,			
			 float *coord_s,
			 int num,
			 int dim,
			 long x,
			 int K){	

	const int thread_id = threadIdx.x + blockIdx.x * blockDim.x;
	const int local_id = threadIdx.x;

	if(thread_id<num){

	  if(0 == local_id)
	   	for(int i=0; i<dim; i++){ 
	   		coord_s[i] = coord_d[i*num + x];
	   	}
